"""
Shared test fixtures and mock implementations.

Provides lightweight mock objects for every ABC so test modules can import
and use them without real external dependencies (OpenAI keys, Qdrant, etc.).
"""

from __future__ import annotations

import asyncio
from typing import Any, AsyncIterator, Iterator
from unittest.mock import MagicMock

import pytest
from langchain_core.messages import AIMessage, BaseMessage, HumanMessage


# ---------------------------------------------------------------------------
# Mock LLM backend
# ---------------------------------------------------------------------------

class MockLLMBackend:
    """Minimal BaseLLMBackend implementation for testing."""

    def __init__(self, response_text: str = "mock response") -> None:
        self._response_text = response_text

    @property
    def model_name(self) -> str:
        return "mock-model"

    @property
    def provider(self) -> str:
        return "mock"

    def invoke(self, messages: list[BaseMessage], **kwargs: Any) -> AIMessage:
        return AIMessage(content=self._response_text)

    async def ainvoke(self, messages: list[BaseMessage], **kwargs: Any) -> AIMessage:
        return AIMessage(content=self._response_text)

    def stream(self, messages: list[BaseMessage], **kwargs: Any) -> Iterator[AIMessage]:
        yield AIMessage(content=self._response_text)

    async def astream(self, messages: list[BaseMessage], **kwargs: Any) -> AsyncIterator[AIMessage]:
        yield AIMessage(content=self._response_text)  # type: ignore[misc]

    def with_structured_output(self, schema: Any) -> Any:
        mock = MagicMock()
        mock.invoke.return_value = {}
        return mock


# ---------------------------------------------------------------------------
# Mock Embedding backend
# ---------------------------------------------------------------------------

class MockEmbeddingBackend:
    """Minimal EmbeddingBackend implementation for testing."""

    def __init__(self, dim: int = 4) -> None:
        self._dim = dim

    @property
    def model_name(self) -> str:
        return "mock-embedder"

    @property
    def dimensions(self) -> int:
        return self._dim

    def embed_query(self, text: str) -> list[float]:
        return [0.1] * self._dim

    def embed_documents(self, texts: list[str]) -> list[list[float]]:
        return [[0.1] * self._dim for _ in texts]

    async def aembed_query(self, text: str) -> list[float]:
        return [0.1] * self._dim

    async def aembed_documents(self, texts: list[str]) -> list[list[float]]:
        return [[0.1] * self._dim for _ in texts]


# ---------------------------------------------------------------------------
# Mock VectorStore backend
# ---------------------------------------------------------------------------

from langchain_core.documents import Document


class MockVectorStoreBackend:
    """In-memory VectorStoreBackend for testing (no similarity scoring)."""

    def __init__(self) -> None:
        self._store: dict[str, list[tuple[Document, str]]] = {}

    def upsert(self, collection: str, documents: list[Document], ids: list[str] | None = None) -> None:
        self._store.setdefault(collection, [])
        for i, doc in enumerate(documents):
            doc_id = (ids[i] if ids else None) or f"doc-{len(self._store[collection])}"
            self._store[collection].append((doc, doc_id))

    async def aupsert(self, collection: str, documents: list[Document], ids: list[str] | None = None) -> None:
        self.upsert(collection, documents, ids)

    def search(self, collection: str, query: str, k: int = 5, **kwargs: Any) -> list[Document]:
        docs = [d for d, _ in self._store.get(collection, [])]
        return docs[:k]

    async def asearch(self, collection: str, query: str, k: int = 5, **kwargs: Any) -> list[Document]:
        return self.search(collection, query, k)

    def delete(self, collection: str, ids: list[str]) -> None:
        if collection in self._store:
            self._store[collection] = [(d, i) for d, i in self._store[collection] if i not in ids]

    async def adelete(self, collection: str, ids: list[str]) -> None:
        self.delete(collection, ids)

    def count(self, collection: str) -> int:
        return len(self._store.get(collection, []))


# ---------------------------------------------------------------------------
# Mock Memory backend
# ---------------------------------------------------------------------------

class MockMemoryBackend:
    """In-memory BaseMemoryBackend for testing."""

    def __init__(self) -> None:
        self._sessions: dict[str, list[BaseMessage]] = {}

    @property
    def backend_name(self) -> str:
        return "mock_memory"

    def add_message(self, session_id: str, message: BaseMessage) -> None:
        self._sessions.setdefault(session_id, []).append(message)

    def get_messages(self, session_id: str, limit: int | None = None) -> list[BaseMessage]:
        msgs = self._sessions.get(session_id, [])
        return msgs[-limit:] if limit else list(msgs)

    def clear(self, session_id: str) -> None:
        self._sessions.pop(session_id, None)

    async def aadd_message(self, session_id: str, message: BaseMessage) -> None:
        self.add_message(session_id, message)

    async def aget_messages(self, session_id: str, limit: int | None = None) -> list[BaseMessage]:
        return self.get_messages(session_id, limit)

    async def aclear(self, session_id: str) -> None:
        self.clear(session_id)


# ---------------------------------------------------------------------------
# Mock Tool
# ---------------------------------------------------------------------------

class MockTool:
    """Minimal BaseTool implementation for testing."""

    @property
    def name(self) -> str:
        return "mock_tool"

    @property
    def description(self) -> str:
        return "A mock tool that echoes its input."

    @property
    def args_schema(self):
        return None

    def run(self, input: str) -> str:
        return f"echo: {input}"

    async def arun(self, input: str) -> str:
        return self.run(input)


# ---------------------------------------------------------------------------
# Pytest fixtures
# ---------------------------------------------------------------------------

@pytest.fixture
def mock_llm() -> MockLLMBackend:
    return MockLLMBackend()


@pytest.fixture
def mock_embedder() -> MockEmbeddingBackend:
    return MockEmbeddingBackend()


@pytest.fixture
def mock_vectorstore() -> MockVectorStoreBackend:
    return MockVectorStoreBackend()


@pytest.fixture
def mock_memory() -> MockMemoryBackend:
    return MockMemoryBackend()


@pytest.fixture
def mock_tool() -> MockTool:
    return MockTool()

"""
Decorators for transparent tracing of LangGraph node functions and LLM calls.

Both sync and async functions are supported. Exceptions are logged to the
active tracer and re-raised so the application continues to behave normally.

Example::

    from cdl_llm.observability.decorators import trace_node, trace_llm_call
    from cdl_llm.observability.noop import NoOpBackend

    tracer = NoOpBackend()

    @trace_node(name="retrieval", tracer=tracer)
    def retrieve_documents(state):
        ...

    @trace_llm_call(tracer=tracer)
    def call_llm(messages):
        ...
"""

from __future__ import annotations

import asyncio
import functools
import time
from typing import Any, Callable, TYPE_CHECKING

if TYPE_CHECKING:
    from .base import BaseTracingBackend

# Module-level default tracer (NoOpBackend by default, lazily initialised)
_default_tracer: BaseTracingBackend | None = None


def set_default_tracer(tracer: BaseTracingBackend) -> None:
    """Set the module-level default tracer used by all decorators.

    Args:
        tracer: The tracing backend to use as the global default.

    Example:
        >>> from cdl_llm.observability.langsmith import LangSmithBackend
        >>> set_default_tracer(LangSmithBackend(api_key="ls__..."))
    """
    global _default_tracer
    _default_tracer = tracer


def _get_tracer(tracer: BaseTracingBackend | None) -> BaseTracingBackend:
    """Return the provided tracer or fall back to the module default."""
    if tracer is not None:
        return tracer
    if _default_tracer is not None:
        return _default_tracer
    from .noop import NoOpBackend

    return NoOpBackend()


def trace_node(
    name: str | None = None,
    tracer: BaseTracingBackend | None = None,
    capture_input: bool = True,
    capture_output: bool = True,
) -> Callable[[Callable], Callable]:
    """Decorator for LangGraph node functions and arbitrary callables.

    Wraps execution in a trace span. Works on both sync and async functions.
    Exceptions are logged to the tracer and re-raised unchanged.

    Args:
        name: Span name. Defaults to the decorated function's ``__name__``.
        tracer: Tracing backend. Defaults to the module-level default.
        capture_input: If ``True``, log the first positional argument as
            ``input_preview`` in the span metadata (truncated to 500 chars).
        capture_output: If ``True``, log the return value as an event.

    Returns:
        A decorator that wraps the target function.

    Example:
        >>> @trace_node(name="my_node")
        ... def my_node_fn(state: dict) -> dict:
        ...     return {"output": "done"}
    """

    def decorator(fn: Callable) -> Callable:
        span_name = name or fn.__name__

        @functools.wraps(fn)
        def sync_wrapper(*args: Any, **kwargs: Any) -> Any:
            t = _get_tracer(tracer)
            meta: dict[str, Any] = {}
            if capture_input and args:
                try:
                    meta["input_preview"] = str(args[0])[:500]
                except Exception:
                    pass
            ctx = t.start_trace(span_name, meta)
            try:
                result = fn(*args, **kwargs)
                if capture_output:
                    t.log_event(ctx, "output", {"preview": str(result)[:500]})
                t.end_trace(ctx, output=str(result)[:500])
                return result
            except Exception as exc:
                t.end_trace(ctx, output="", error=str(exc))
                raise

        @functools.wraps(fn)
        async def async_wrapper(*args: Any, **kwargs: Any) -> Any:
            t = _get_tracer(tracer)
            meta: dict[str, Any] = {}
            if capture_input and args:
                try:
                    meta["input_preview"] = str(args[0])[:500]
                except Exception:
                    pass
            ctx = t.start_trace(span_name, meta)
            try:
                result = await fn(*args, **kwargs)
                if capture_output:
                    t.log_event(ctx, "output", {"preview": str(result)[:500]})
                t.end_trace(ctx, output=str(result)[:500])
                return result
            except Exception as exc:
                t.end_trace(ctx, output="", error=str(exc))
                raise

        if asyncio.iscoroutinefunction(fn):
            return async_wrapper
        return sync_wrapper

    return decorator


def trace_llm_call(
    tracer: BaseTracingBackend | None = None,
) -> Callable[[Callable], Callable]:
    """Decorator for methods or functions that make LLM calls.

    Logs latency and delegates output logging to the tracer.
    Works on both sync and async functions.

    Args:
        tracer: Tracing backend. Defaults to the module-level default.

    Returns:
        A decorator that wraps the target function.

    Example:
        >>> @trace_llm_call()
        ... def invoke_llm(messages):
        ...     return llm.invoke(messages)
    """

    def decorator(fn: Callable) -> Callable:
        @functools.wraps(fn)
        def sync_wrapper(*args: Any, **kwargs: Any) -> Any:
            t = _get_tracer(tracer)
            ctx = t.start_trace(f"llm_call:{fn.__name__}", {})
            start = time.monotonic()
            try:
                result = fn(*args, **kwargs)
                latency_ms = (time.monotonic() - start) * 1000
                # Try to extract token usage from AIMessage
                usage: dict[str, Any] = {}
                if hasattr(result, "usage_metadata") and result.usage_metadata:
                    usage = {
                        "input_tokens": getattr(
                            result.usage_metadata, "input_tokens", 0
                        ),
                        "output_tokens": getattr(
                            result.usage_metadata, "output_tokens", 0
                        ),
                    }
                t.log_event(
                    ctx, "llm_call_complete", {"latency_ms": latency_ms, **usage}
                )
                content = getattr(result, "content", str(result))
                t.end_trace(ctx, output=str(content)[:200])
                return result
            except Exception as exc:
                t.end_trace(ctx, output="", error=str(exc))
                raise

        @functools.wraps(fn)
        async def async_wrapper(*args: Any, **kwargs: Any) -> Any:
            t = _get_tracer(tracer)
            ctx = t.start_trace(f"llm_call:{fn.__name__}", {})
            start = time.monotonic()
            try:
                result = await fn(*args, **kwargs)
                latency_ms = (time.monotonic() - start) * 1000
                usage: dict[str, Any] = {}
                if hasattr(result, "usage_metadata") and result.usage_metadata:
                    usage = {
                        "input_tokens": getattr(
                            result.usage_metadata, "input_tokens", 0
                        ),
                        "output_tokens": getattr(
                            result.usage_metadata, "output_tokens", 0
                        ),
                    }
                t.log_event(
                    ctx, "llm_call_complete", {"latency_ms": latency_ms, **usage}
                )
                content = getattr(result, "content", str(result))
                t.end_trace(ctx, output=str(content)[:200])
                return result
            except Exception as exc:
                t.end_trace(ctx, output="", error=str(exc))
                raise

        if asyncio.iscoroutinefunction(fn):
            return async_wrapper
        return sync_wrapper

    return decorator

