{
  description = "cdl-llm-platform — LLM deployment platform";

  inputs = {
    nixpkgs.url     = "github:NixOS/nixpkgs/nixos-unstable";
    flake-utils.url = "github:numtide/flake-utils";
    devenv.url      = "github:cachix/devenv";
    uv2nix.url      = "github:pyproject-nix/uv2nix";
    uv2nix.inputs.nixpkgs.follows = "nixpkgs";
  };

  outputs = { self, nixpkgs, flake-utils, devenv, uv2nix }:
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = nixpkgs.legacyPackages.${system};
        overlays = import ./nix/overlays.nix { };
        pkgsWithOverlays = import nixpkgs { inherit system; overlays = overlays; };

        pythonEnv = import ./nix/python-env.nix { pkgs = pkgsWithOverlays; };
      in {
        # ── Dev shell for platform contributors ──────────────────────────────
        devShells.default = devenv.lib.mkShell {
          inherit inputs pkgs;
          modules = [{
            languages.python = {
              enable  = true;
              version = "3.11";
              uv.enable = true;
            };

            packages = with pkgs; [
              just
              docker-compose
              git
            ];

            enterShell = ''
              uv sync --extra dev
              echo "cdl-llm-platform dev environment ready"
              echo "Run: llm-platform --help"
            '';

            pre-commit.hooks = {
              ruff.enable        = true;
              ruff-format.enable = true;
              mypy.enable        = true;
            };
          }];
        };

        # ── Base Docker image for all services ────────────────────────────────
        packages.base-image = import ./nix/base-image.nix {
          pkgs = pkgsWithOverlays;
          inherit pythonEnv;
        };

        # ── Chainlit base Docker image for frontends ──────────────────────────
        packages.chainlit-base-image = import ./nix/chainlit-base-image.nix {
          pkgs = pkgsWithOverlays;
        };

        # ── CLI as a Nix package ──────────────────────────────────────────────
        packages.llm-platform = pkgs.python311Packages.buildPythonApplication {
          pname   = "cdl-llm-platform";
          version = "0.2.0";
          src     = ./.;
          format  = "pyproject";

          nativeBuildInputs = with pkgs.python311Packages; [ hatchling ];

          propagatedBuildInputs = with pkgs.python311Packages; [
            typer
            rich
            pydantic
            pydantic-settings
            jinja2
            pyyaml
            httpx
            python-dotenv
            gitpython
          ];
        };

        # ── Default package — install with: nix run ───────────────────────────
        packages.default = self.packages.${system}.llm-platform;

        # ── CI checks ─────────────────────────────────────────────────────────
        checks = {
          tests = pkgs.runCommand "platform-tests"
            {
              buildInputs = [
                pkgs.python311
                pythonEnv
              ];
            }
            ''
              cd ${./.}
              ${pkgs.python311}/bin/python -m pytest tests/ -v
              touch $out
            '';
        };
      }
    );
}

# nix/base-image.nix
# Shared base Docker image for all cdl-llm services.
# Built with Nix — minimal, reproducible, no shell by default.
# All services use FROM this image in their Dockerfiles.
#
# Build: nix build .#base-image
# Load:  docker load < result
{ pkgs, pythonEnv }:

pkgs.dockerTools.buildLayeredImage {
  name = "cdl-llm-base";
  tag  = "v0.1.0";

  # Minimal contents — no shell, no package manager
  contents = [
    pythonEnv          # Python 3.11 + cdl-llm library pre-installed
    pkgs.cacert        # SSL certificates for HTTPS connections
    pkgs.tzdata        # Timezone data
  ];

  # Create non-root user and working directory
  extraCommands = ''
    # Create the app user (uid 1001) in /etc/passwd
    mkdir -p etc
    echo "app:x:1001:0:App User:/app:/sbin/nologin" >> etc/passwd
    echo "app:x:1001:" >> etc/group

    # Create the app working directory
    mkdir -p app
    chown 1001:0 app
  '';

  config = {
    # Run as non-root user (uid 1001)
    User       = "1001";
    WorkingDir = "/app";
    Env = [
      "PYTHONUNBUFFERED=1"
      "PYTHONDONTWRITEBYTECODE=1"
      "SSL_CERT_FILE=${pkgs.cacert}/etc/ssl/certs/ca-bundle.crt"
      "PATH=${pythonEnv}/bin:/usr/local/bin"
    ];
    # No CMD — services override this in their own Dockerfiles
  };
}

