{
  description = "cdl-llm-platform — LLM deployment platform";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixpkgs-unstable";
    flake-parts.url = "github:hercules-ci/flake-parts";
  };

  outputs = inputs@{ self, flake-parts, ... }:
    flake-parts.lib.mkFlake { inherit inputs; } {
      systems = [ "x86_64-linux" "aarch64-linux" "aarch64-darwin" "x86_64-darwin" ];

      perSystem = { config, self', inputs', pkgs, system, ... }:
        let
          overlays = import ./nix/overlays.nix { };
          pkgsWithOverlays = import inputs.nixpkgs { inherit system overlays; };
          pythonEnv = import ./nix/python-env.nix { pkgs = pkgsWithOverlays; };
        in
        {
          # ── Dev shell for platform contributors ──────────────────────────────
          devShells.default = pkgs.mkShell {
            packages = with pkgs; [
              python312

              # Tooling
              ruff
              mypy
              just
              docker-compose
              git

              # Nix formatting
              nixfmt

              # Native deps
              pkg-config
              openssl.dev
            ];

            env = {
              CDL_LLM_TRACING_BACKEND = "noop";
              LD_LIBRARY_PATH = "${pkgs.openssl.out}/lib";
            };

            shellHook = ''
              echo "🦇 cdl-llm-platform dev shell activated"
              echo "   Python: ${pkgs.python312.version}"
              echo "   Run: pip install -e '.[dev]' && llm-platform --help"
            '';
          };

          # ── Base Docker image for all services ────────────────────────────────
          packages.base-image = import ./nix/base-image.nix {
            pkgs = pkgsWithOverlays;
            inherit pythonEnv;
          };

          # ── Chainlit base Docker image for frontends ──────────────────────────
          packages.chainlit-base-image = import ./nix/chainlit-base-image.nix {
            pkgs = pkgsWithOverlays;
          };

          # ── CLI as a Nix package ──────────────────────────────────────────────
          packages.llm-platform = pkgs.python312Packages.buildPythonApplication {
            pname = "cdl-llm-platform";
            version = "0.2.0";
            src = ./.;
            format = "pyproject";

            nativeBuildInputs = with pkgs.python312Packages; [ hatchling ];

            propagatedBuildInputs = with pkgs.python312Packages; [
              typer
              rich
              pydantic
              pydantic-settings
              jinja2
              pyyaml
              httpx
              python-dotenv
              gitpython
            ];
          };

          packages.default = config.packages.llm-platform;

          # ── CI checks ─────────────────────────────────────────────────────────
          checks = {
            tests = pkgs.runCommand "platform-tests"
              {
                buildInputs = [
                  pkgs.python312
                  pythonEnv
                ];
              }
              ''
                cd ${./.}
                ${pkgs.python312}/bin/python -m pytest tests/ -v
                touch $out
              '';
          };

          formatter = pkgs.nixfmt;
        };
    };
}

